class Solution:
    def reachNumber(self, target: int) -> int:
        target = abs(target)
        low, high = 1, target
        res = 0
        while low <= high:
            mid = (low + high) // 2
            total = mid * (mid + 1) // 2
            if total >= target and (total - target) % 2 == 0:
                res = mid
                break
            elif total < target:
                low = mid + 1
            else:
                high = mid - 1
        return res
